from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Helper to format a list with commas and "and"
    def fmt_list(items: list[str]) -> str:
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    # Index triples by subject preserving order of first appearance
    from collections import defaultdict
    subj_map: dict[str, list[Triple]] = defaultdict(list)
    order: list[str] = []
    for t in triples:
        subj_map[t.subject].append(t)
        if t.subject not in order:
            order.append(t.subject)

    sentences: list[str] = []

    for subj in order:
        parts: list[str] = []
        triples_here = subj_map[subj]

        # ----- genre -----
        genre_objs = [t.object for t in triples_here if t.predicate == "genre"]
        if genre_objs:
            genre_phrase = f"{subj} is a {genre_objs[0].lower()} artist"
            # stylistic origin of the genre (genre as subject)
            origins = [t.object for t in triples if t.subject == genre_objs[0] and t.predicate == "stylisticOrigin"]
            if origins:
                genre_phrase += f", originating from {origins[0].lower()}"
            parts.append(genre_phrase)

        # ----- associated band / musical artist (multiple) -----
        assoc_objs = [t.object for t in triples_here if t.predicate == "associatedBand/associatedMusicalArtist"]
        if assoc_objs:
            parts.append(f"{subj} is associated with {fmt_list(assoc_objs)}")

        # ----- instrument (multiple) -----
        instr_objs = [t.object for t in triples_here if t.predicate == "instrument"]
        if instr_objs:
            # Assume the subject is a person/artist and plays the listed instrument(s)
            parts.append(f"{subj} plays the {fmt_list(instr_objs)}")

        # ----- occupation (single) -----
        occ_objs = [t.object for t in triples_here if t.predicate == "occupation"]
        if occ_objs:
            occ = occ_objs[0].lower()
            # add article if not already present
            if not occ.startswith(("a ", "an ", "the ")):
                occ = "a " + occ
            parts.append(f"{subj} is {occ}")

        # ----- birth / death / origin info -----
        for t in triples_here:
            p, o = t.predicate, t.object
            if p in ("birthDate", "birthYear"):
                parts.append(f"{subj} was born in {o}")
            elif p in ("deathDate", "deathPlace"):
                parts.append(f"{subj} died in {o}")
            elif p == "birthPlace":
                parts.append(f"{subj} was born in {o}")
            elif p == "origin":
                parts.append(f"{subj} originates from {o}")
            elif p == "nationality":
                parts.append(f"{subj} is {o}")
            elif p == "recordLabel":
                # try to enrich record label with its location if known
                loc = None
                for t2 in triples:
                    if t2.subject == o and t2.predicate == "location":
                        loc = t2.object
                        break
                if loc:
                    parts.append(f"{subj} is signed to {o}, which is based in {loc}")
                else:
                    parts.append(f"{subj} is signed to {o}")
            elif p == "background":
                parts.append(f"{subj} has a background as {o}")
            elif p == "activeYearsStartYear":
                parts.append(f"{subj} started activity in {o}")
            elif p == "activeYearsEndYear":
                parts.append(f"{subj} ended activity in {o}")

        # ----- relational predicates where object is primary -----
        relational_predicates = {
            "leader", "capital", "currency", "anthem", "parentCompany", "location",
            "governingBody", "leaderTitle", "country", "isPartOf", "derivative",
            "bandMember"
        }
        # ----- genre‑related predicates where subject is a genre -----
        genre_predicates = {
            "musicFusionGenre": "has a fusion genre",
            "musicSubgenre": "has subgenre",
            "stylisticOrigin": "originated from"
        }
        for t in triples_here:
            if t.predicate in relational_predicates:
                # more natural phrasing for each predicate
                if t.predicate == "location":
                    parts.append(f"{subj} is located in {t.object}")
                elif t.predicate == "capital":
                    parts.append(f"{subj} has capital {t.object}")
                elif t.predicate == "currency":
                    parts.append(f"{subj} uses the {t.object}")
                elif t.predicate == "anthem":
                    parts.append(f"The anthem of {subj} is {t.object}")
                elif t.predicate == "parentCompany":
                    parts.append(f"{subj} is owned by {t.object}")
                elif t.predicate == "leader":
                    parts.append(f"The leader of {subj} is {t.object}")
                elif t.predicate == "leaderTitle":
                    parts.append(f"The leader of {subj} holds the title {t.object}")
                elif t.predicate == "governingBody":
                    parts.append(f"The governing body of {subj} is {t.object}")
                elif t.predicate == "country":
                    parts.append(f"{subj} is in {t.object}")
                elif t.predicate == "isPartOf":
                    parts.append(f"{subj} is part of {t.object}")
                elif t.predicate == "derivative":
                    parts.append(f"{subj} is a derivative of {t.object}")
                elif t.predicate == "bandMember":
                    parts.append(f"{t.object} is a member of {subj}")
            elif t.predicate in genre_predicates:
                # phrasing for genre‑related predicates where the subject is a genre
                relation = genre_predicates[t.predicate]
                if t.predicate == "stylisticOrigin":
                    parts.append(f"{subj} {relation} {t.object.lower()}")
                else:
                    parts.append(f"{subj} {relation} {t.object}")

        # Combine parts for this subject into a single sentence
        if parts:
            sentence = fmt_list(parts)
            # Capitalise first character
            sentence = sentence[0].upper() + sentence[1:] + "."
            sentences.append(sentence)

    # Join all subject‑level sentences with a space
    return " ".join(sentences)

# EVOLVE-BLOCK-END

